package com.democorp.dfp.execution;

/** Synthetic DFP code for DREAM codebase memory demos. */
import java.time.Instant; import java.util.HashMap; import java.util.Map; public class StatusTracker { private final Map<String, ExecutionStatus> executionStatuses = new HashMap<>(); private final Map<String, Instant> lastUpdated = new HashMap<>(); public void markExecutionQueued(String executionId) { persistStatus(executionId, ExecutionStatus.QUEUED); } public void markExecutionRunning(String executionId) { persistStatus(executionId, ExecutionStatus.RUNNING); } public void markExecutionCompleted(String executionId) { persistStatus(executionId, ExecutionStatus.COMPLETED); } public void markExecutionFailed(String executionId) { persistStatus(executionId, ExecutionStatus.FAILED); } public void markPartialSuccess(String executionId) { persistStatus(executionId, ExecutionStatus.PARTIAL_SUCCESS); } public boolean isStaleRunning(String executionId, Instant now) { return executionStatuses.get(executionId) == ExecutionStatus.RUNNING && lastUpdated.containsKey(executionId) && lastUpdated.get(executionId).plusSeconds(900).isBefore(now); } private void persistStatus(String executionId, ExecutionStatus status) { executionStatuses.put(executionId, status); lastUpdated.put(executionId, Instant.now()); } }
